def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    exp_cache = {}
    log_cache = {}
    sin_cache = {}
    cos_cache = {}
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        if ratio not in exp_cache:
            exp_cache[ratio] = np.exp(-ratio)
            log_cache[ratio] = np.log1p(ratio)
            sin_cache[ratio] = np.sin(ratio * 3.14)
            cos_cache[ratio] = np.cos(ratio * 2.71)
        exp_neg = exp_cache[ratio]
        log_val = log_cache[ratio]
        sin_val = sin_cache[ratio]
        cos_val = cos_cache[ratio]
        priority = 0
        if ratio > 8:
            sum1 = 0
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 6) / (a * b + 1.1)
                    sum1 += val * np.tanh(ratio * b / (a + 2))
            priority = sum1 + (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 1.7
            if i % 2 == 0:
                priority += np.sin(item * ratio * i * 0.05) * 5
            else:
                priority -= np.cos(item * ratio * i * 0.04) * 4.7
        elif 5 < ratio <= 8:
            s = 0
            for x in range(1, int(np.ceil(ratio)) + 5):
                for y in range(1, x + 4):
                    term = ((ratio - x) ** 4) * np.cos(ratio * y) / (y + 0.8)
                    s += np.tanh(term) * 1.5
            priority = s + np.sqrt(ratio) * 8 - np.tanh(ratio - 5) * 3
            for z in range(1, 6):
                priority += np.sin(ratio * z * i) * ((ratio - 5) ** z) / z
        elif 2 <= ratio <= 5:
            s = 0
            for n in range(1, 15):
                s += ((ratio - 2) ** n) / (n * 1.6) * np.sin(n * ratio * 1.1)
            priority = (s * np.cos(9 * ratio)) - np.log1p(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            if bin_cap < item * 1.3:
                priority += np.sqrt(item / (bin_cap + 1)) * 3.5
            else:
                priority -= np.cos(25 * ratio) * 3
        elif 1 <= ratio < 2:
            s = 0
            for m in range(1, 12):
                factor = ((2 - ratio) ** m) / (m ** 2 + 0.3)
                s += factor * np.cos(m * 2.5 * ratio)
            if bin_cap < item:
                penalty = np.sqrt(item / (bin_cap + 0.9)) * 5
            else:
                penalty = np.sin(30 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for p in range(1, 7):
                priority += np.sin(p * ratio * i * 0.8) * ((ratio - 1) ** p) / p
        elif 0.4 <= ratio < 1:
            s = 0
            for q in range(1, 18):
                s += ((1 - ratio) ** q) / (q * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.2) + 2.5)
            for r in range(1, 8):
                priority += ((1 - ratio) ** r) * np.sin(r * item * 1.5) * 0.8
        elif 0.15 <= ratio < 0.4:
            s = 0
            for t in range(1, 15):
                s += ((0.4 - ratio) ** t) / (t * 3) * np.cos(t * ratio * 2.3)
            priority = s + 2 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for u in range(1, 9):
                priority += ((0.4 - ratio) ** u) / (u * 7) * np.cos(item * u * 0.9)
        else:
            s = 0
            for v in range(1, 12):
                s += ((0.15 - ratio) ** v) / (v * 6) * np.sin(v * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for w in range(1, 10):
                priority += ((0.15 - ratio) ** w) / (w * 8) * np.cos(item * w * 1.0)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 7
            priority += np.sin(item * bin_cap * 0.2) * 3
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
            priority -= np.cos(bin_cap * 0.1) * 3
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
                priority += np.cos(item * idx) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.4
                priority -= np.sin(item * idx) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7 + np.cos(item * i * 0.3) * 0.6
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7 + np.sin(item * i * 0.3) * 0.6
        if item > 10:
            extra = 0
            for z in range(1, int(min(item, 12))):
                extra += np.tanh((item - z) / (bin_cap + z * 0.5)) * np.sin(z * ratio)
            priority += extra * 2.3
        priorities[i] = priority
    return priorities
